original:
.ico_defeat_a { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_a 1s ease 1; }
.ico_defeat_b { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_b 1s ease 1; }
.ico_defeat_c { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_c 1s ease 1; }
.ico_defeat_d { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d 1s ease 1; }
@keyframes ani_defeat_a { 0% { transform: translate(8px, 8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
@keyframes ani_defeat_b { 0% { transform: translate(-8px, 8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
@keyframes ani_defeat_c { 0% { transform: translate(-8px, -8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
@keyframes ani_defeat_d { 0% { transform: translate(8px, -8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
